class MessageContext:
    def __init__(self, message, consumer: KafkaConsumer, config: ConsumerConfig):
        self.message = message
        self.consumer = consumer
        self.config = config

    @property
    def topic(self) -> str:
        return self.message.topic

    @property
    def partition(self) -> int:
        return self.message.partition

    @property
    def offset(self) -> int:
        return self.message.offset

    @property
    def key(self) -> Any:
        return self.message.key

    @property
    def timestamp(self) -> int:
        return self.message.timestamp

    def commit(self) -> None:
        tp = TopicPartition(self.message.topic, self.message.partition)
        self.consumer.commit(offsets={tp: self.message.offset + 1})


